import{_ as e,o as a,c as p,j as r,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const D=JSON.parse('{"title":"漠风流","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/白刃类/九剑/漠风流.md","filePath":"4.资源分区/6.技艺及称号/武技类/白刃类/九剑/漠风流.md"}'),s={name:"4.资源分区/6.技艺及称号/武技类/白刃类/九剑/漠风流.md"};function o(d,b,l,_,i,c){return a(),p("div",null,[...b[0]||(b[0]=[r("h1",{id:"漠风流",tabindex:"-1"},[t("漠风流 "),r("a",{class:"header-anchor",href:"#漠风流","aria-label":'Permalink to "漠风流"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风021")])])],-1),n('<h1 id="漠风流-1" tabindex="-1">漠风流 <a class="header-anchor" href="#漠风流-1" aria-label="Permalink to &quot;漠风流&quot;">​</a></h1><p>漠风流<br> “九剑”乃是传承自神秘世界的一系列玄奇的武术。<br> 漠风流的招数主要由高速的移动和跃动的火焰结合而成。许多漠风流招数中的复杂动作和弯刀刀法其实是可以召唤火焰的精妙手势。在修习漠风流招式后，你获得等同于最高的漠风流招式支线等级的施法者职能，仅限于与火焰相关的法术。<br> 漠风流的偏好武器是刀，钉头锤，十字镐，枪与矛。</p><p>D级：<br> 避火诀（架势技）<br> 价格：D+500<br> 发动时间：迅捷动作<br> 距离：自身<br> 目标：自身<br> 持续时间：一场景，或直到切换为另一种架势<br> 描述：火焰并不是你的敌人，也不会伤害你。<br> 效果：当你启动这种架势后，你获得等同于你运动技能附加成功数*2的火焰抗力。</p><p>红莲之剑（强化技）<br> 价格：D+500<br> 发动时间：迅捷动作<br> 距离：自身<br> 目标：自身<br> 持续时间：本轮结束<br> 描述：当你发动这种招数后，你的武器迸发出火焰，以优雅的轨迹向对手击去。手中的武器微妙而精确地颤动着，释放出炽热的力量。<br> 效果：本回合内你的攻击获得2DP加值和1点附加成功，这是火焰能量加值，你的攻击将造成火焰能量伤害。</p><p>风行（强化技）<br> 价格：D+500<br> 发动时间：迅捷动作<br> 距离：自身<br> 目标：自身<br> 持续时间：本轮<br> 描述：你迅速地移动，在周围带起阵阵暖风。漠风带着你在战场穿梭，让你拥有更好的速度穿越对手。<br> 效果：你的基础移动速度增加20米，并且不会陷入C级措手不及，持续一回合。<br> 磨练：你依次花费C+1000/B+2000升级这个技能。你将该技能提供的移速加值改为+65/245米，并使免疫措手不及等级提升到B/A级。</p><p>炎阳冲（攻击技）<br> 价格：D+500<br> 发动时间：整轮动作<br> 距离：按冲锋处理<br> 目标：自身<br> 持续时间：立即<br> 描述：你由空中向目标冲去，好像化为一道耀眼的火焰。<br> 效果：你在此次冲锋中获得与陆行速度相同的飞行能力，拥有普通机动力。直到你的回合结束，你的脚底附着一层赤色的火焰将托着你缓缓着落，保护你不受自然坠落伤害。除此以外，冲锋按正常规则处理。炽热的火焰灼烧目标的身躯，如果你的攻击命中，则可以造成1点额外的韧性伤害。</p><p>焰星缭乱（攻击技）<br> 价格：D+500<br> 消耗：1点通用能量<br> 发动时间：标准动作<br> 距离：10米<br> 范围：自身为圆点，10米，不分敌我<br> 描述：你用武器在头顶画个圈子，武器就变成火焰。随着你手臂的动作，火焰炸裂成耀眼的闪光。<br> 效果：对自身周围除你以外的所有目标进行一次攻击，附带等同于伤害出目的目眩点数，正常豁免，可叠加。</p><p>漠风（攻击技）<br> 价格：D+500<br> 前提：2种漠风流招数<br> 发动时间：整轮动作<br> 距离：自身<br> 目标：自身<br> 描述：你像到残像般移动，穿梭在战场攻击所有擦身而过的对手，身后只留下焦黑的痕迹。<br> 效果：作为招数的一部分，你按基础速度进行移动，最多移动一倍基础速度的距离。对移动路径上的所有触及范围内的目标进行一次白刃攻击。你不能用这种招数多次攻击相同的目标。</p><p>业火延烧（攻击技）<br> 价格：D+500<br> 发动时间：标准动作<br> 距离：近战攻击<br> 目标：单个目标<br> 持续时间：一回合<br> 描述：舞动的蓝色火焰出现在武器周围，随着你的攻击，业火由武器延烧到你的对手，让他周身覆盖在烈焰中。<br> 效果：你对目标发动一次近战白刃攻击，本次攻击获得3点增强加值。若你的攻击命中，武器的火焰会附着在目标的周身，在本回合内降低对方3点盔甲或天生防御（盔甲防御优先），并附带1点火焰易伤。数值不可叠加。</p><p>雏龙之焰（攻击技）<br> 价格：D+500<br> 发动时间：整轮动作<br> 距离：5米<br> 范围：以自身为中心<br> 持续时间：立即<br> 描述：你把火焰的能量集中在刀尖，形成高热的一点，接着迸发出可怕的能量。<br> 漠风流教导门徒把气以火焰能量的形势放出。你可以用这种招数制造出火浪横扫对手。当使用这种招数后，你可以用澎湃的刀芒制造出锥形火焰。<br> 效果：对以自身为中心，5M范围内的目标进行一次白刃普通攻击，此次攻击不通过防御，而是以反射豁免。</p><p>C级：<br> 烈焰屏障（架势技）<br> 前提：1种漠风流招数<br> 价格：C+1000<br> 发动时间：迅捷动作<br> 距离：自身<br> 目标：自身<br> 持续时间：一场景，或直到切换为另一种架势<br> 描述：剑脊的火焰随着你的动作在周围旋转，沐浴在你的周身，对你发动攻击的生物都会因此而灼伤。<br> 效果：当你启动这种架势后，你在偏斜防御上获得2点提升。若处于你近战触及范围内的敌人对你发动攻击，则会被火焰反噬，受到3点火焰严重伤害的反伤。</p><p>凤凰诀（架势技）<br> 价格：C+1000<br> 发动时间：迅捷动作<br> 距离：自身<br> 目标：自身<br> 持续时间：一场景，或直到切换为另一种架势<br> 描述：炽热的空气在你的脚边盘旋，把你托在空中，好像脚底有团舞动的火焰。<br> 效果：高热气体可以把你托在空中。当你启动这种架势后。你获得与陆行速度相同的飞行速度，拥有普通的机动性。此外，只要依旧处于该架势下，你就能获得6点偏斜防御。</p><p>西风之舞<br> 价格：C+1000<br> 前提：1种漠风流招数<br> 发动时间：标准动作<br> 距离：自身<br> 目标：自身<br> 持续时间：见下<br> 描述：你优雅地在对手的攻击间舞动，好像沙漠的西风滑过黄沙。你灵敏地左右闪避，对手的攻击根本没法碰到你的衣角。<br> 效果：你需要消费一个标准动作进行准备，随后在该场景内只要受到攻击，就可以立刻使用一个无需消费AP的反射动作执行移动，这次移动具有打断性，每轮你只能享受一次该能力提供的移动效果。</p><p>焰之蛇（攻击技）<br> 价格：C+1000<br> 发动时间：标准动作<br> 距离：力量/2米<br> 范围：特殊<br> 持续时间：立即<br> 描述：你把武器插进地面，让熊熊的火焰喷射到空中。火焰落到地面，开始蜿蜒蛇行，横扫你的对手，把他们烧成炭渣。<br> 效果：<br> 当你发动这种招数后，你可以制造一条线形火焰横扫区域灼烧你的对手。火线宽度1米，长度为力量/2米。与标准线形不同，火蛇可以随意弯曲转向，对于途径范围内所有敌对单位发动一次普通白刃攻击，造成严重火焰伤害。火蛇必须在地面上延着效果线移动，火蛇不能飞行。</p><p>B级：<br> 死之莲印（攻击技）<br> 价格：B+2000<br> 发动时间：整轮动作<br> 距离：近战攻击<br> 目标：单体生物<br> 范围：可变扩散<br> 持续时间：立即<br> 描述：当你的武器击中对手后，把武器中火焰送进对方的身体，最终由体内爆裂出来。<br> 效果：当你发动这种招数后，你把火焰的能量送进目标的体内。使用时需要消费整轮动作，对触及范围内的任一单位进行一次白刃普通攻击。<br> 命中后除了正常伤害外，你还可以让火焰按扩散方式由目标的体内爆裂出来，爆裂半径等同15+自身力量附加*10米，对范围内的所有敌对目标造成第二次攻击，也包括你的攻击目标，需要进行反射豁免。当然，你也可以选择将第一次攻击同样改为第二次攻击一样进行范围攻击与使敌对目标采用反射豁免，而非正常防御流程。</p><p>真龙之焰（攻击技）<br> 前提：此技艺可由雏龙之焰差价升级<br> 价格：B+2500<br> 发动时间：标准动作<br> 距离：20米<br> 范围：扇形<br> 持续时间：见下<br> 描述：你的宝剑划出旋转的弧线。随着每次的旋转，烈焰都在不断增强。随着一阵闪光，你停住手中的剑，指向你的对手，发出滚滚的烈焰。<br> 效果：漠风流的宗师可以通过旋转他们的武器引发威力极强的火焰爆裂，使用标准动作对前方20M扇形范围内的敌对目标进行一次白刃普通攻击，目标以反射豁免。<br> 所攻击的扇形区域将持续被炽热的火焰所覆盖，常人难以接近。直到下个回合开始前，若敌对目标处于该范围内，则将再承受一次同样的攻击，这是一个B级环境来源带来的效果。</p><p>A级：<br> 红莲之阵<br> 价格：A+4000<br> 发动时间：整轮动作启动<br> 距离：特殊；参阅描述<br> 范围：特殊；参阅描述<br> 描述：你像道残像般移动，脚边围绕着火焰的能量。随着你的移动，你身后形成一道火线。当你用火线围绕住对手后，你形成的火焰阵炸裂出地狱的业火，吞没你的对手和所有在区域内的目标。<br> 效果：作为招式的一部分，你可以使用自身基础速度在地面移动，但即使你的移动速度足够，最多也只能移动自身敏捷*20米。你会在移动时留下一道火线，这道火线本身没有任何伤害作用，直到他们形成封闭的区域为止。<br> 封闭的区域一旦形成，狂怒的地狱业火会在区域内爆发，包括你在内，所有停留在火线区域内的单位会受到一次你的普通白刃攻击，受影响单位必须使用反射检定豁免你的普通白刃攻击检定造成的伤害值，若失败则无法离开封闭区域，唯一不同的是你和友方单位无需承受这次攻击检定造成的伤害。</p><p>只要仍处于只封闭区域中，所有敌对目标就必须每轮额外承受你的一次不附带招式的白刃近战攻击，所有在区域内的生物都会受到相当于成功数的严重火焰伤害，反射减免。<br> 这是A级环境来源的异空间效果，在效果影响范围内禁止A级及A级以下的传送能力及传送攻击能力。<br> 红莲之阵会在你完成一次封闭区域后立刻启动，效果持续一场景。你不可以利用一次移动形成多个封闭区域。</p><p>S级：<br> 业火爆裂（攻击技）<br> 价格：S+8000<br> 发动时间：标准动作<br> 范围：以自身为中心敏感范围半径爆发<br> 持续时间：立即<br> 描述：炽热的空气在你身边盘旋，周围充满硫磺的气味。你周身的黄色光芒变得越来亮，放出滚滚热浪。你周围的生物因为高温步步后退。随着狂怒的嗥叫，你炸裂出地狱的业火，周围的钢铁和岩石都渐渐融化。<br> 效果：以一个标准动作你把体内的气集成耀眼的高热火焰，对对范围内所有敌对目标进行一次普通白刃攻击，造成韧性伤害，附带【超级贯穿】特性，目标以反射豁免，若失败则立刻死亡，这是一个S级环境来源的即死效果。若你对本次攻击结果不满意，则可以进行一次重骰，必须接受结果，且这一效果每轮只会生效一次。<br> 若目标成功豁免或是免疫了这次即死，则还会受到等同于伤害出目的耐力伤害，耐力伤害使用强韧豁免，这一属性伤害会进入毁灭性状态，这是S级创伤来源的效果。</p><hr><p>Copyright ? 2024 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',21)])])}const f=e(s,[["render",o]]);export{D as __pageData,f as default};
